codeExample:
-- Session-level lock (phải manual unlock)
SELECT pg_advisory_lock(12345);
-- critical section
SELECT pg_advisory_unlock(12345);

-- Transaction-level lock (tự release khi commit/rollback)
BEGIN;
SELECT pg_advisory_xact_lock(42);
-- critical section
COMMIT; -- lock tự release

-- Try lock (non-blocking)
SELECT pg_try_advisory_lock(789); -- trả true/false ngay lập tức

-- C# wrapper
public async Task<bool> TryAcquireDistributedLockAsync(
    string lockName, CancellationToken ct)
{
    // Hash lockName sang bigint
    long lockKey = (long)lockName.GetHashCode();
    var result = await db.Database.SqlQueryRaw<bool>(
        "SELECT pg_try_advisory_xact_lock({0})", lockKey)
        .FirstAsync(ct);
    return result;
}

// Scheduled job pattern
public async Task RunExclusiveJobAsync(string jobName, CancellationToken ct)
{
    await using var tx = await db.Database.BeginTransactionAsync(ct);
    bool locked = await TryAcquireDistributedLockAsync(jobName, ct);
    if (!locked)
    {
        _logger.LogInformation("Job {Job} đang chạy trên instance khác — bỏ qua", jobName);
        return;
    }
    await ExecuteJobAsync(ct);
    await tx.CommitAsync(ct); // lock release
}
